/**
 * Severity defines the criticality level of an alert.
 */
export type Severity = "critical" | "warning" | "info";

/**
 * AlertStatus defines the current lifecycle state of an alert.
 */
export type AlertStatus = "active" | "acknowledged" | "resolved";

/**
 * Alert represents a system alert generated by the monitoring service.
 *
 * @property id - Unique identifier for the alert.
 * @property title - Brief summary of the alert.
 * @property message - Detailed description of the issue.
 * @property severity - Criticality level of the alert.
 * @property status - Current state of the alert.
 * @property service - The name of the service that generated the alert.
 * @property timestamp - Time when the alert was generated (ISO 8601).
 * @property source - The origin or component source of the alert.
 */
export interface Alert {
  id: string;
  title: string;
  message: string;
  severity: Severity;
  status: AlertStatus;
  service: string;
  timestamp: string; // ISO string
  source: string;
}

/**
 * AlertRule defines a condition that triggers an alert when met.
 *
 * @property id - Unique identifier for the rule.
 * @property name - Human-readable name of the rule.
 * @property metric - The metric being monitored (e.g., "cpu_usage").
 * @property operator - The comparison operator (e.g., ">", "<").
 * @property threshold - The value to compare the metric against.
 * @property duration - The duration the condition must persist before triggering.
 * @property severity - The severity level assigned to alerts from this rule.
 * @property enabled - Whether the rule is currently active.
 * @property last_updated - Timestamp of the last rule update.
 */
export interface AlertRule {
  id: string;
  name: string;
  metric: string;
  operator: string;
  threshold: number;
  duration: string;
  severity: Severity;
  enabled: boolean;
  last_updated?: string;
}
